import { useState } from 'react';

function EditObject({ doubleClickedObjId, objects, setObjects }) {
    const [currentShape, setCurrentShape] = useState('Circle');

    function newColor(color) {
        setObjects(
            objects.map((el) =>
                el.id === doubleClickedObjId ? { ...el, color: color } : el,
            ),
        );
    }

    function newShape(shape) {
        function doShape() {
            setObjects(
                objects.map((el) =>
                    el.id === doubleClickedObjId ? { ...el, shape: '50%' } : el,
                ),
            );
        }

        currentShape === "Circle"
    }

    const selectedObject = objects.find((el) => el.id === doubleClickedObjId);

    return (
        <div className="editObj">
            <h2>Edit object</h2>
            <div className="editColor">
                <div className="editColorButtons">
                    <button
                        className="colEditGreen"
                        onClick={() => newColor('green')}
                    />
                    <button
                        className="colEditBlue"
                        onClick={() => newColor('blue')}
                    />
                    <button
                        className="colEditYellow"
                        onClick={() => newColor('yellow')}
                    />
                    <button
                        className="colEditGrey"
                        onClick={() => newColor('grey')}
                    />
                    <button
                        className="colEditWhite"
                        onClick={() => newColor('white')}
                    />
                    <button
                        className="colEditPurple"
                        onClick={() => newColor('purple')}
                    />
                    <button
                        className="colEditCyan"
                        onClick={() => newColor('cyan')}
                    />
                    <button
                        className="colEditLime"
                        onClick={() => newColor('lime')}
                    />
                    <button
                        className="colEditRed"
                        onClick={() => newColor('red')}
                    />
                    <button
                        className="colEditBrown"
                        onClick={() => newColor('brown')}
                    />
                    <button
                        className="colEditOrange"
                        onClick={() => newColor('orange')}
                    />
                    <button
                        className="colEditLightBlue"
                        onClick={() => newColor('lightblue')}
                    />
                    <button
                        className="colEditPink"
                        onClick={() => newColor('pink')}
                    />
                    <button
                        className="colEditDarkStaleGrey"
                        onClick={() => newColor('darkslategrey')}
                    />
                </div>
                <p className="objPropName">Color</p>
            </div>
            <div className="editButtonForm">
                <button
                    className="objForm"
                    style={{
                        backgroundColor: selectedObject.color,
                    }}
                />
                <p className="objPropName">Circle</p>
            </div>
        </div>
    );
}

export default EditObject;
